    "AuthorizePathwaysReport": { "label": "Authorize Pathways Report", "type": "boolean", "colspan": 6 }
  },
  "Personal Background Information": {
    "_sectionTitle": "Personal Background Information",
    "_order": 6,
    "Have you ever been certified or otherwise authorized to teach in any jurisdiction outside of New Brunswick?": { "label": "Certified to teach outside New Brunswick?", "colspan": 12 },
    "Have you ever applied anywhere for authorization and/or certification to teach and had your application denied?\n": { "label": "Teaching certification application ever denied?", "colspan": 12 },
    "Has your authorization and/or certification to teach ever been suspended or cancelled in another jurisdiction?\n": { "label": "Teaching certification ever suspended or cancelled?", "colspan": 12 },
    "Have you ever, for any reason other than a failure to pay fees, voluntarily surrendered your authorization and/or certification to teach?\n": { "label": "Ever voluntarily surrendered teaching certification?", "colspan": 12 },
    "Have you ever, in advance of an investigation or disciplinary proceeding, voluntarily restricted your teaching practice?\n": { "label": "Ever voluntarily restricted teaching practice?", "colspan": 12 },
    "Have you ever been found guilty of professional misconduct or been found to be incompetent or incapacitated in relation to the teaching profession?\n": { "label": "Found guilty of professional misconduct?", "colspan": 12 },
    "Has there ever been, or is there now, an investigation or proceeding with respect to your professional conduct, competence or capacity in relation to the teaching profession, including in your teacher education program?\n": { "label": "Any current or past investigations regarding professional conduct?", "colspan": 12 },
    "Have you ever been asked by a teacher education program provider to withdraw from a teacher education program?\n": { "label": "Ever asked to withdraw from teacher education program?", "colspan": 12 },
    "Have you ever been personally prevented from carrying on your occupation as a teacher as a result of any criminal, civil, or disciplinary proceeding?\n": { "label": "Ever prevented from teaching due to legal proceedings?", "colspan": 12 },
    "Have you ever agreed to a settlement or resignation to avoid a proceeding or disciplinary action with respect to your professional conduct, competence, or capacity, in relation to either a teaching position or your professional certification?\n": { "label": "Ever settled/resigned to avoid disciplinary action?", "colspan": 12 },
    "Have you ever been terminated or had restrictions imposed on your employment as a teacher by an employing school district, education authority, or other organization with respect to your conduct, competence, or capacity?\n": { "label": "Ever terminated or restricted as a teacher?", "colspan": 12 },
    "Have you ever been subject to an investigation or proceeding relating to working with children or students in any professional capacity?\n": { "label": "Ever investigated for conduct with children/students?", "colspan": 12 },
    "Is there any other information you know that may have a bearing on you being granted a teacher's certificate?\n": { "label": "Any other relevant information?", "colspan": 12 }
  }
}
